// friday13.cs — Friday the 13th experiments with the proleptic Gregorian calendar

// 1. Find the earliest Friday the 13th starting from 0001-01-01
var date = new DateTime(1, 1, 13); // start on the 13th of January, year 1
while (date.DayOfWeek != DayOfWeek.Friday)
    date = date.AddMonths(1);

Console.WriteLine($"Earliest Friday the 13th: {date:yyyy-MM-dd} ({date.DayOfWeek})");

// 2. Count Friday the 13ths in a full 400-year Gregorian cycle (years 1–400)
int count = 0;
var monthDate = new DateTime(1, 1, 13);
var cycleEnd = new DateTime(401, 1, 13);

while (monthDate < cycleEnd)
{
    if (monthDate.DayOfWeek == DayOfWeek.Friday)
        count++;
    monthDate = monthDate.AddMonths(1);
}

Console.WriteLine($"Friday the 13ths in a 400-year cycle: {count}");
Console.WriteLine($"Average per year: {count / 400.0:F4}");

// 3. Bonus: distribution by month
var byMonth = new int[12];
monthDate = new DateTime(1, 1, 13);
while (monthDate < cycleEnd)
{
    if (monthDate.DayOfWeek == DayOfWeek.Friday)
        byMonth[monthDate.Month - 1]++;
    monthDate = monthDate.AddMonths(1);
}

Console.WriteLine("\nDistribution by month (400-year cycle):");
for (int m = 0; m < 12; m++)
    Console.WriteLine($"  {new DateTime(2000, m + 1, 1):MMMM,-12} {byMonth[m]}");

